class HotelAPIClient{constructor(t=null){if(t)this.baseURL=t;else{const t=window.location.hostname.includes("onrender.com");this.baseURL=t?"https://sinan-han-hotel.onrender.com":"http://localhost:5000"}this.cache={},this.cacheTimeout=36e5,console.log(`🔗 API Client initialized with baseURL: ${this.baseURL}`)}async request(t,e={}){const c=`${this.baseURL}/api${t}`;try{const t=await fetch(c,{method:e.method||"GET",headers:{"Content-Type":"application/json",...e.headers},body:e.body?JSON.stringify(e.body):void 0});if(!t.ok)throw new Error(`API Error: ${t.status} ${t.statusText}`);return await t.json()}catch(e){throw console.error(`❌ API Request Failed (${t}):`,e),e}}async getHotel(){if(this.cache.hotel&&this.isValidCache("hotel"))return this.cache.hotel;try{const t=await this.request("/hotel");return this.cache.hotel={data:t,timestamp:Date.now()},t}catch(t){return console.error("Failed to fetch hotel data:",t),null}}async getPrices(){if(this.cache.prices&&this.isValidCache("prices"))return this.cache.prices;try{const t=await this.request("/hotel/prices");return this.cache.prices={data:t,timestamp:Date.now()},t}catch(t){return console.error("Failed to fetch prices:",t),null}}async getPolicies(){if(this.cache.policies&&this.isValidCache("policies"))return this.cache.policies;try{const t=await this.request("/hotel/policies");return this.cache.policies={data:t,timestamp:Date.now()},t}catch(t){return console.error("Failed to fetch policies:",t),null}}async getCancellationPolicy(){if(this.cache.cancellation&&this.isValidCache("cancellation"))return this.cache.cancellation;try{const t=await this.request("/hotel/cancellation");return this.cache.cancellation={data:t,timestamp:Date.now()},t}catch(t){return console.error("Failed to fetch cancellation policy:",t),null}}async getPrivacyPolicy(){if(this.cache.privacy&&this.isValidCache("privacy"))return this.cache.privacy;try{const t=await this.request("/hotel/privacy");return this.cache.privacy={data:t,timestamp:Date.now()},t}catch(t){return console.error("Failed to fetch privacy policy:",t),null}}async createBooking(t){try{return await this.request("/bookings",{method:"POST",body:t})}catch(t){throw console.error("Failed to create booking:",t),t}}isValidCache(t){const e=this.cache[t];return!!e&&Date.now()-e.timestamp<this.cacheTimeout}clearCache(t=null){t?delete this.cache[t]:this.cache={}}}const hotelAPI=new HotelAPIClient;